import * as fields from '../../../../../assets/src/index.tsx'
import userEvent from '@testing-library/user-event'
import { 
  render, 
  within 
} from '@testing-library/react'
import { 
  rendersWithMinimal,
  rendersWithoutLabelThrowWarning,
  rendersLabelAndDescription
} from '../../../utils/fields.ts'

describe('Checkbox component', () => {

  it('renders with minimal config', () => rendersWithMinimal({ type: 'checkbox' }))
  it('renders when no label but throws a warning', () => rendersWithoutLabelThrowWarning({ type: 'checkbox' }))
  it('renders label and description', () => rendersLabelAndDescription({ type: 'checkbox' }))

  it('triggers checked change if label is clicked', async () => {

    const user = userEvent.setup()
    const { container } = render( 
      fields.render({
        label   : 'Click on label',
        name    : 'checkbox-name',
        type    : 'checkbox',
      })
    )

    const input = container.querySelector('input[type="checkbox"]')
    expect(input.checked).toBe(false)

    await user.click(within(container).getByText('Click on label'))

    expect(input.checked).toBe(true)
  })
})

import {
  forwardRef,
  useRef
} from 'react'

import { Checkbox as TuiCheckbox, Field } from '@tangible/ui'

export interface FieldsCheckboxProps {
  value?: boolean | '1' | '0'
  onChange?: (value: boolean) => void
  label?: string
  labelVisuallyHidden?: boolean
  description?: string
  descriptionVisuallyHidden?: boolean
  isDisabled?: boolean
  isRequired?: boolean
  name?: string
  className?: string
}

const Checkbox = forwardRef<HTMLInputElement, FieldsCheckboxProps>((props, ref) => {

  const {
    value,
    onChange,
    label,
    labelVisuallyHidden,
    description,
    descriptionVisuallyHidden,
    isDisabled,
    isRequired,
    name,
    className,
  } = props

  const warnedRef = useRef(false)
  if (!warnedRef.current && !label) {
    warnedRef.current = true
    console.warn('Checkbox: Missing label. Provide a label prop for accessibility.')
  }

  /**
   * Derive boolean checked state directly from the value prop.
   * When value is provided, TUI Checkbox is fully controlled — no local state needed.
   * External changes (e.g. repeater bulk-select) are reflected automatically.
   */
  const boolValue = value === '1' || value === true
  const controlledProps = value !== undefined
    ? { checked: boolValue }
    : { defaultChecked: false }

  const labelContent = label
    ? labelVisuallyHidden
      ? <span className="tui-visually-hidden">{label}</span>
      : label
    : undefined

  return (
    <div className="tf-checkbox">
      <Field
        className={className}
        required={Boolean(isRequired)}
        disabled={Boolean(isDisabled)}
      >
        <TuiCheckbox
          ref={ref}
          label={labelContent}
          {...controlledProps}
          disabled={Boolean(isDisabled)}
          onCheckedChange={nextChecked => {
            if (onChange) onChange(nextChecked)
          }}
        />
        <input type="hidden" name={name ?? ''} value={boolValue ? '1' : '0'} />
        {description && (
          <Field.HelperText className={descriptionVisuallyHidden ? 'tui-visually-hidden' : undefined}>
            {description}
          </Field.HelperText>
        )}
      </Field>
    </div>
  )
})

export default Checkbox

import { forwardRef } from 'react'

import { Switch as TuiSwitch, Field } from '@tangible/ui'

export interface FieldsSwitchProps {
  value?: boolean | '1' | '0'
  onChange?: (value: boolean) => void
  label?: string
  labelVisuallyHidden?: boolean
  description?: string
  descriptionVisuallyHidden?: boolean
  isDisabled?: boolean
  name?: string
  className?: string
}

const Switch = forwardRef<HTMLButtonElement, FieldsSwitchProps>((props, ref) => {

  const {
    value,
    onChange,
    label,
    labelVisuallyHidden,
    description,
    descriptionVisuallyHidden,
    isDisabled,
    name,
    className,
  } = props

  /**
   * Derive boolean checked state directly from the value prop.
   * When value is provided, TUI Switch is fully controlled — no local state needed.
   * TUI onCheckedChange only fires on user interaction, not on mount.
   */
  const boolValue = value === '1' || value === true
  const controlledProps = value !== undefined
    ? { checked: boolValue }
    : { defaultChecked: false }

  const labelContent = label
    ? labelVisuallyHidden
      ? <span className="tui-visually-hidden">{label}</span>
      : label
    : undefined

  return (
    <div className="tf-switch">
      <Field
        className={className}
        disabled={Boolean(isDisabled)}
      >
        <TuiSwitch
          ref={ref}
          label={labelContent}
          {...controlledProps}
          disabled={Boolean(isDisabled)}
          onCheckedChange={nextChecked => {
            if (onChange) onChange(nextChecked)
          }}
        />
        <input type="hidden" name={name ?? ''} value={boolValue ? '1' : '0'} />
        {description && (
          <Field.HelperText className={descriptionVisuallyHidden ? 'tui-visually-hidden' : undefined}>
            {description}
          </Field.HelperText>
        )}
      </Field>
    </div>
  )
})

export default Switch

import { forwardRef } from 'react'

import { RadioGroup as TuiRadioGroup, Field } from '@tangible/ui'

export interface FieldsRadioGroupProps {
  value?: string
  onChange?: (value: string) => void
  label?: string
  description?: string
  isDisabled?: boolean
  isRequired?: boolean
  name?: string
  className?: string
  children?: React.ReactNode
}

/**
 * <RadioGroup label="Radio label">
 *   <Radio value="2">Value 1</Radio>
 *   <Radio value="1">Value 2</Radio>
 * </RadioGroup>
 */

const RadioGroup = forwardRef<HTMLDivElement, FieldsRadioGroupProps>((props, ref) => {

  const {
    value,
    onChange,
    label,
    description,
    isDisabled,
    isRequired,
    name,
    className,
    children,
  } = props

  const controlledProps = value !== undefined
    ? { value }
    : { defaultValue: '' }

  return (
    <div ref={ref} className="tf-radio-group">
      <Field
        className={className}
        required={Boolean(isRequired)}
        disabled={Boolean(isDisabled)}
      >
        {label && <Field.Label>{label}</Field.Label>}
        <TuiRadioGroup
          {...controlledProps}
          disabled={Boolean(isDisabled)}
          onValueChange={val => {
            if (onChange) onChange(String(val))
          }}
        >
          {children}
        </TuiRadioGroup>
        <input type="hidden" name={name ?? ''} value={value ?? ''} />
        {description && (
          <Field.HelperText>{description}</Field.HelperText>
        )}
      </Field>
    </div>
  )
})

export { RadioGroup }

import { forwardRef } from 'react'
import { Radio as TuiRadio } from '@tangible/ui'

export interface FieldsRadioProps {
  value: string
  children?: React.ReactNode
  isDisabled?: boolean
  className?: string
  id?: string
}

const Radio = forwardRef<HTMLButtonElement, FieldsRadioProps>((props, ref) => {

  const {
    value,
    children,
    isDisabled,
    className,
  } = props

  return (
    <TuiRadio
      ref={ref}
      value={value}
      label={children}
      disabled={Boolean(isDisabled)}
      className={className}
    />
  )
})

export default Radio

