import {
  useRef,
  useState,
  useEffect,
  lazy,
  Suspense,
  forwardRef,
} from 'react'

import { useTextField } from 'react-aria'
import { Field, Textarea as TuiTextarea } from '@tangible/ui'
import type { SizeStandard } from '@tangible/ui'
import { Description, Label } from '../../base'

const DynamicEditor = lazy(() => import('../../dynamic/editor/DynamicEditor'))

export interface FieldsTextareaProps {
  dynamic?: unknown
  value?: string
  onChange?: (value: string) => void
  name?: string
  label?: string
  labelVisuallyHidden?: boolean
  description?: string
  descriptionVisuallyHidden?: boolean
  placeholder?: string
  readOnly?: boolean
  isDisabled?: boolean
  isRequired?: boolean
  isInvalid?: boolean
  error?: boolean
  className?: string
  maxlength?: number
  minlength?: number
  rows?: number
  required?: boolean
  identifier?: string
  size?: SizeStandard
}

/**
 * Dynamic path sub-component — rendered only when the `dynamic` prop is set.
 * Isolated here so `useTextField` (react-aria) is only called in this path.
 */
const DynamicTextarea = (props: FieldsTextareaProps) => {
  const [value, setValue] = useState(props.value ?? '')
  const ref = useRef<HTMLTextAreaElement | null>(null)
  const mountedRef = useRef(false)

  const {
    labelProps,
    inputProps,
    descriptionProps,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } = useTextField({ ...props, inputElementType: 'textarea' } as any, ref as any)

  useEffect(() => {
    if (!mountedRef.current) {
      mountedRef.current = true
      return
    }
    if (props.onChange) props.onChange(value)
  }, [value])

  return (
    <div className="tf-text-area tf-text-area-dynamic">
      {props.label &&
        <Label labelProps={labelProps} parent={props}>
          {props.label}
        </Label>}
      <Suspense fallback={null}>
        <DynamicEditor
          value={value}
          onChange={setValue}
          dynamic={props.dynamic}
          name={props.name}
          placeholder={props.placeholder}
          readOnly={props.readOnly}
          singleLine={false}
          inputProps={inputProps}
        />
      </Suspense>
      {props.description && (
        <Description descriptionProps={descriptionProps} parent={props}>
          {props.description}
        </Description>
      )}
    </div>
  )
}

/**
 * Textarea with two routing paths:
 * 1. dynamic → ProseMirror-based DynamicEditor (multi-line)
 * 2. plain → TUI Textarea + Field compound
 */
const TextArea = forwardRef<HTMLTextAreaElement, FieldsTextareaProps>((props, ref) => {
  const hasDynamic = Boolean(props.dynamic)

  if (hasDynamic) {
    return <DynamicTextarea {...props} />
  }

  return (
    <div className='tf-text-area'>
      <Field
        className={props.className}
        required={Boolean(props.isRequired)}
        disabled={Boolean(props.isDisabled || props.readOnly)}
        error={Boolean(props.isInvalid || props.error)}
      >
        {props.label &&
          <Field.Label hidden={Boolean(props.labelVisuallyHidden)}>
            {props.label}
          </Field.Label>}
        <Field.Control>
          <TuiTextarea
            ref={ref}
            size={props.size}
            placeholder={props.placeholder}
            readOnly={props.readOnly}
            rows={props.rows}
            maxLength={props.maxlength}
            minLength={props.minlength}
            required={props.required}
            name={props.name}
            value={props.value ?? ''}
            onChange={event => {
              if (props.onChange) props.onChange(event.target.value)
            }}
            data-identifier={props.identifier ?? ''}
          />
        </Field.Control>
        {props.description && (
          <Field.HelperText className={props.descriptionVisuallyHidden ? 'tui-visually-hidden' : undefined}>
            {props.description}
          </Field.HelperText>
        )}
      </Field>
    </div>
  )
})

export default TextArea

import { forwardRef } from 'react'
import type { ReactNode } from 'react'
import { Notice as TuiNotice } from '@tangible/ui'
import type { NoticeProps as TuiNoticeProps } from '@tangible/ui'

type TuiNoticeTheme = NonNullable<TuiNoticeProps['theme']>

export interface FieldsNoticeProps {
  message?: ReactNode
  type?: 'success' | 'error' | 'warning' | 'info'
  onDismiss?: () => void
  className?: string
}

const typeToTheme: Record<string, TuiNoticeTheme> = {
  error: 'danger',
  success: 'success',
  warning: 'warning',
  info: 'info',
}

const Notice = forwardRef<HTMLElement, FieldsNoticeProps>(function Notice(
  { message, type, onDismiss, className },
  ref
) {
  const theme = type ? (typeToTheme[type] ?? 'info') : undefined
  const classes = ['tf-notice', className].filter(Boolean).join(' ')

  return (
    <TuiNotice
      ref={ref as never}
      theme={theme}
      dismissible={!!onDismiss}
      onDismiss={onDismiss}
      className={classes}
    >
      <TuiNotice.Body>{message}</TuiNotice.Body>
    </TuiNotice>
  )
})

export default Notice

import { 
  render,
  screen
} from '@testing-library/react'
import * as fields from '../../../assets/src/index.tsx'

const rendersWithMinimal = ({
  type,
  expectedClass
}) => {

  const { container } = render(
    fields.render({
      type  : type,
      label : `Label for ${type}`
    }
  ))

  const classes = container.firstChild.firstChild.classList
  expect(classes.contains(expectedClass ?? `tf-${type}`)).toEqual(true)
}

const rendersWithoutLabelThrowWarning = ({
  type,
  expectedClass
}) => {

  console.warn = jest.fn()

  const { container } = render(
    fields.render({
      type : type
    }
  ))

  const classes = container.firstChild.firstChild.classList

  expect(classes.contains(expectedClass ?? `tf-${type}`)).toEqual(true)
  expect(console.warn).toHaveBeenCalled()
}

const rendersLabelAndDescription = ({
  type,
  expectedClass
}) => {

  const { container } = render(
    fields.render({
      type        : type,
      label       : `Label for ${type}`,
      description : `Description for ${type}`
    }
  ))

  const classes = container.firstChild.firstChild.classList

  expect(classes.contains(expectedClass ?? `tf-${type}`)).toEqual(true)

  const label = screen.getByText(`Label for ${type}`)
  const description = screen.getByText(`Description for ${type}`)

  expect(label).toBeTruthy()
  expect(description).toBeTruthy()
}

const renderHasElement = (config, getElement) => {

  const { container } = render(fields.render(config))
  const element = getElement(container)

  expect(element).toBeTruthy()
}

const renderHasNotElement = (config, getElement) => {

  const { container } = render(fields.render(config))
  const element = getElement(container)

  expect(element).toBeFalsy()
} 

export {
  rendersWithMinimal,
  rendersWithoutLabelThrowWarning,
  rendersLabelAndDescription,
  renderHasElement,
  renderHasNotElement
}

import * as fields from '../../../../../assets/src/index.tsx'
import userEvent from '@testing-library/user-event'
import { render, within } from '@testing-library/react'

describe('Field group component', () => {

  it('renders with elements inside fields', () => {

    const { container } = render(
      <>
        { fields.render({
          name   : 'field-group-name',
          type   : 'field-group',
          fields : [
            {
              type    : 'description',
              content : 'Test 1',
              name    : 'subfield1',
            },
            {
              label   : 'Subfield 2',
              type    : 'text',
              name    : 'subfield2'
            },
          ]
        }) }
      </>
    )

    const fieldGroup = container.querySelectorAll('.tf-field-group')
    expect(fieldGroup.length).toBe(1)

    expect(container.querySelector('.tf-description'))
    expect(within(container).getByText('Test 1')).toBeTruthy()

    expect(container.querySelector('.tf-text'))
    expect(within(container).getByText('Subfield 2')).toBeTruthy()

  })

  it('renders with repeater inside field', async () => {

    const user = userEvent.setup()
    const { container } = render(
      <>
        { fields.render({
          name   : 'field-group-name',
          type   : 'field-group',
          value  : '{"advanced":[{"advanced_text":"test"},{"key":"613b35d6811aa8","advanced_text":"test2"}]}',
          fields : [
            {
              type    : 'repeater',
              layout  : 'advanced',
              name    : 'advanced',
              fields  : [
                {
                  type  : 'text',
                  label : 'Text label',
                  name  : 'advanced_text'
                }
              ]
            }
          ]
        }) }
      </>
    )

    const fieldGroup = container.querySelectorAll('.tf-field-group')
    expect(fieldGroup.length).toBe(1)

    const openButton = container.querySelectorAll('.tf-button-repeater-overview-open')
    expect(openButton)

    await user.click(openButton[0])
    expect(container.querySelector('.tf-text')).toBeTruthy()
    expect(container.querySelectorAll('.tf-text').length).toBe(1)

    await user.click(openButton[1])
    expect(container.querySelector('.tf-text')).toBeTruthy()
    expect(container.querySelectorAll('.tf-text').length).toBe(1)

  })

  it('renders with visibility condition inside fields', async () => {

    const user = userEvent.setup()
    const { container } = render(
      <>
        { fields.render({
          name   : 'field-group-name',
          type   : 'field-group',
          fields : [
            {
              label     : 'Subfield 1',
              type      : 'switch',
              name      : 'subfield1',
            },
            {
              label     : 'Subfield 2',
              type      : 'text',
              name      : 'subfield2',
              condition : {
                action    : 'show',
                condition : {
                  subfield1 : { '_eq' : 'on' }
                }
              }
            },
          ]
        }) }
      </>
    )

    const fieldGroup = container.querySelectorAll('.tf-field-group')
    expect(fieldGroup.length).toBe(1)

    await user.click(container.querySelector('[role="switch"]'))

    const subfield2 = await within(container).findByText('Subfield 2')
    expect(subfield2).toBeTruthy()

    await user.click(container.querySelector('[role="switch"]'))

    expect(within(container).queryByText('Subfield 2')).toBe(null)
  })
})

import { 
  render, 
  createRoot 
} from 'react-dom'

import { createContext } from 'react'

import {
  config,
  getConfig,
  setConfig
} from './config'

import { 
  triggerEvent,
  addEventListener 
} from './events'

import Control from './Control'
import Element from './Element'
import store from './store'
import types from './types'
import fields from './fields'
import * as utils from './utils'

/**
 * Used to detect the current context from child components
 */
const ControlContext = createContext(null)

const renderComponent = (props, type = 'field') => (
  type === 'element' 
    ? renderElement(props)
    : renderField(props)
)

const renderField = props => (
  <ControlContext.Provider value={{
    name            : props.context ?? 'default',
    wrapper         : `tf-context-${props.context ?? 'default'} tui-interface`,
    getValue        : store.getValue.bind(store),
    portalContainer : props.portalContainer ?? document.body
  }}>
    <Control 
      { ...props } 
      onChange={ value => {
        store._setValueFromControl(props.name, value)
        if( props.onChange ) props.onChange(value)
      }}
      visibility={{

import { OverlayProvider } from 'react-aria'
import { 
  useContext,
  useEffect
} from 'react'
import { ControlContext } from './index.tsx'

import types from './types.ts'
import DependendWrapper from './components/dependent/DependendWrapper'
import VisibilityWrapper from './components/visibility/VisibilityWrapper'
import RenderWrapper from './components/render/RenderWrapper.tsx'

/**
 * Really similar to Control component, expect it has no values
 */
const Element = ({
  visibility,
  data,
  afterInitialization = false,
  ...props
}) => {

  /**
   * @see renderElement() in ./src/index.jsx 
   */
  const control = useContext(ControlContext)

  const wrapper = {
    ...(props.wrapper ?? {}),
    className: `${props?.wrapper?.class ?? ''} ${control.wrapper}`
  }
  delete wrapper.class

  useEffect(() => {
    if ( afterInitialization ) afterInitialization() // Not set for subfields
  }, [])

  const ElementComponent = types.get(props.type ?? false, 'element')
  if (!ElementComponent) return <></>;

  return (
    <OverlayProvider { ...wrapper }>
      <VisibilityWrapper visibility={ visibility } data={ data }>
        <RenderWrapper 
